var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"제프티 바이오테크, 방호 구축 실험지구.\\n<color=#ffd34c>윌버 웨이틀리</color> 대표, 시설 방문 중 ","JPN":"ジェフティ・バイオテック、防護構築実験地区。\\n<color=#ffd34c>ウィルバー・ウェイトリー</color>代表、施設訪問中","ENG":"Jehuty Biotech Defensive Measures Test Zone\\nCEO\xA0<color=#ffd34c>Wilbur Whateley</color> conducting site visit","TWN":"傑夫堤生物科技，防護機制實驗機構。\\n<color=#ffd34c>韋爾伯·韋特利</color>代表親臨設施中 ","SCN":"杰普提生物科技，防护构建实验地区。\\n<color=#ffd34c>韦尔伯·维特利</color>，正在访问设施。 ","DEU":"[[","FRA":"Jehuty Biotech, zone d'expérimentation protégée.\\nVisite des bureaux du président <color=#ffd34c>Wilbur Whateley</color> "},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"소식은 전해 들었습니다, 대표님. 이렇게 다시 뵙게 되어 영광입니다.","JPN":"お話は聞いております、代表。再びこうしてお会いできて光栄です。","ENG":"I heard the news, sir. It's an honor to meet you again.","TWN":"代表，事情我已經聽說了，很榮幸再次見到您。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"오랜만이야. 그러고 보니 이 시설 담당자가 자네였지.","JPN":"久しぶりだな。そういえばこの施設の担当者は君だったな。","ENG":"Long time no see. I just remembered you're in charge here.","TWN":"好久不見，這麼說來，這棟設施的負責人是你對吧。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"자기야, 이 분들은 혹시…….","JPN":"ダーリン、この方たちは……","ENG":"Babe, are these folks…","TWN":"親愛的，他們是……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"아, 너무 무서워하지 마. 겉모습만 이렇지 이 사람들도 다 내 직원들이니까.","JPN":"あまり怖がる必要はないよ。見た目は少し怖いかもしれないけど、みんなうちの社員さ。","ENG":"Oh, there's no need to be so scared. They may look intimidating, but they all work for me.","TWN":"不用怕，他們也都是我的員工，只是長得比較兇狠而已。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"그렇습니다. 예전에 잠시 범죄 조직에 몸을 담았을 뿐, 지금은 어엿한 제프티 바이오테크 소속이죠.","JPN":"そのとおりです。以前、しばらく犯罪組織に\\n携わっていただけで、今はれっきとしたジェフティ・バイオテック所属です。","ENG":"That's right. We may have been affiliated with a criminal organization briefly, but we're all legitimate employees of Jehuty Biotech now.","TWN":"是的，雖然以前曾經誤入歧途，但現在是屬於正派公司 傑夫堤生物科技的員工。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"시설 담당자로서 방문을 환영합니다, 사모님.","JPN":"施設担当者として訪問を歓迎します、奥様。","ENG":"Please allow me to welcome you as this site's manager, Mrs. Whateley.","TWN":"夫人，我代表設施歡迎您來訪。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"사, 사모님이라니요……. 결혼, 아직인데…….","JPN":"お、奥様だなんて……結婚は、まだなのに……","ENG":"M-missus…? But we haven't gotten married… yet.","TWN":"夫…什麼夫人啦……我們又還沒結婚……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"하하, 이 친구가 확실히 말재주가 좋아.","JPN":"アハハ、空気も読めてユーモアもある人だな。いいぞ。","ENG":"Haha, this fella sure has a way with words.","TWN":"哈哈～嘴真還真甜。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"리플레이서 신디케이트 시절에는 이제 더 미련 없나?","JPN":"リプレイサー・シンジケート時代にもう未練はないのか？","ENG":"Do you really have no regrets about moving on from the Syndicate days?","TWN":"克隆集團的事你已經都放下了嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"그럼요. 킹의 유지를 잇겠다고 설치는 자들은 극히 일부에 불과합니다.","JPN":"もちろんです。キングの遺志を継ぐなどと騒ぐ者は、ごく一部に過ぎません。","ENG":"Of course not. Only a select few remain fanatical enough to continue the legacy of King.","TWN":"當然，吵著說要繼承帝皇遺志的人，只有極少部分而已。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"조직이 무너진 이상 저희들도 각자 살 길을 찾아야죠.","JPN":"組織が崩壊した以上、私たちも各自生きる道を探さなければなりません。","ENG":"Now that the organization has disbanded, we've all got to find our own way to make our living.","TWN":"組織解散後，我們也就分道揚鑣了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"흐음. 그 말을 들으니 우리 회사에서 지내기는 어떤지 궁금해지는군.","JPN":"ほう、そう言われるとうちの会社に所属した感想が気になってくるな。","ENG":"Hmm... That reminds me, I'm curious how accommodating you've found this company.","TWN":"嗯，你聽這麼說，反而有點好奇，那在我們公司做事感覺如何？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"더할 나위 없이 훌륭합니다.","JPN":"この上なく素晴らしいです。","ENG":"Oh, it couldn't be better.","TWN":"棒到不行。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"특히 그로니아 반군들과 제휴해서 실험체를 대량 조달한다는 발상은 무척 흥미롭더군요.","JPN":"特にグロニア反乱軍と提携して、実験体を大量調達するという発想はとても興味深いです。","ENG":"I'm particularly intrigued by the notion of partnering with the Gronia insurgents to secure a mass supply of test subjects.","TWN":"尤其是和格羅尼亞叛軍合作，大量取得實驗體的想法，根本是神來一筆。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"쉬운 협상 상대는 아니었지. 최근에는 대가로 기상 조절기까지 빼돌리게 해 줬으니까.","JPN":"簡単な交渉相手ではなかった。最近は取引の対価として気象調節機まで横流ししてやったからな。","ENG":"They drove a hard bargain. Recently, I've even had to let them pilfer a weather controller.","TWN":"他們可不好應付呢，最近才幫他們弄到氣象調節器而已。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};